#define THREADS_PER_BLOCK 256

typedef struct {
  float weight;
  long assign;  
  float cost;  
} Point_Struct;

__kernel void pgain_kernel(
    const global Point_Struct* p,
    const global float* coord,
    global float* work_mem,
    const global int* center_table,
    global char* switch_membership,
    long x,
    int K,
    int num,
    int dim) {

    int i = get_global_id(0);
    if (i >= num) return;

    // Calculate distance to candidate center x
    float x_cost = 0.0f;
    for (int d = 0; d < dim; d++) {
        float diff = coord[d * num + i] - coord[d * num + x];
        x_cost += diff * diff;
    }
    x_cost *= p[i].weight;

    float current_cost = p[i].cost;

    if (x_cost < current_cost) {
        switch_membership[i] = 1;
        work_mem[i * (K + 1) + K] += (x_cost - current_cost);
    } else {
        int assign = p[i].assign;
        int ct_idx = center_table[assign];
        if (ct_idx >= 0 && ct_idx < K) {
            work_mem[ct_idx] += (current_cost - x_cost);
        }
    }
}

__kernel void pgain_finalize_kernel(
    global Point_Struct* p,
    const global float* coord,
    const global int* center_table,
    const global char* switch_membership,
    const global float* gl_lower,
    long x,
    int K,
    int num,
    int dim) {

    int i = get_global_id(0);
    if (i >= num) return;

    int assign = p[i].assign;
    int ct_idx = center_table[assign];

    bool close_center = (ct_idx >= 0 && ct_idx < K && gl_lower[ct_idx] > 0.0f);

    if (switch_membership[i] == 1 || close_center) {
        float new_cost = 0.0f;
        for (int d = 0; d < dim; d++) {
            float diff = coord[d * num + i] - coord[d * num + x];
            new_cost += diff * diff;
        }
        p[i].cost = new_cost * p[i].weight;
        p[i].assign = x;
    }
}

__kernel void update_centers_kernel(
    global char* is_center,
    const global int* center_table,
    const global float* gl_lower,
    int num) {

    int i = get_global_id(0);
    if (i >= num) return;

    int ct_idx = center_table[i];
    if (is_center[i] && ct_idx >= 0 && gl_lower[ct_idx] > 0.0f) {
        is_center[i] = 0;
    }
}

__kernel void set_center_kernel(
    global char* is_center,
    long x,
    int num) {
    if (x < num) {
        is_center[x] = 1;
    }
}
